class Solution:
    def minDeletions(self, s: str) -> int:
        from collections import Counter
        freqs = sorted(Counter(s).values(), reverse=True)
        deletions = 0
        cap = None
        for f in freqs:
            if cap is None:
                allowed = f
            elif f < cap:
                allowed = f
            else:
                allowed = cap - 1
            if allowed < 0:
                allowed = 0
            deletions += f - allowed
            cap = allowed
        return deletions

