var minDeletions = function(s) {
    const counts = new Map();
    for (const ch of s) {
        counts.set(ch, (counts.get(ch) || 0) + 1);
    }
    const freqs = Array.from(counts.values()).sort((a, b) => b - a);
    let deletions = 0;
    let cap = null;
    for (const f of freqs) {
        let allowed;
        if (cap === null) {
            allowed = f;
        } else if (f < cap) {
            allowed = f;
        } else {
            allowed = cap - 1;
        }
        if (allowed < 0) allowed = 0;
        deletions += f - allowed;
        cap = allowed;
    }
    return deletions;
};
